package com.careeros.discovery.application;
import com.careeros.application.domain.*;import com.careeros.job.domain.*;import com.careeros.matching.application.*;import com.careeros.preference.domain.*;import com.careeros.watchlist.domain.*;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
import java.time.*;import java.time.temporal.ChronoUnit;import java.util.*;import java.util.stream.*;
@Service @Transactional(readOnly=true) public class DailyDiscoveryService{
 private final JobPostingRepository jobs;private final UserPreferenceRepository prefs;private final JobMatchingService matching;private final JobApplicationRepository applications;private final WatchlistRepository watchlists;
 public DailyDiscoveryService(JobPostingRepository j,UserPreferenceRepository p,JobMatchingService m,JobApplicationRepository a,WatchlistRepository w){jobs=j;prefs=p;matching=m;applications=a;watchlists=w;}
 public Dashboard dashboard(){var all=jobs.findAll(JobPostingFilter.empty(),PageRequest.of(0,500,Sort.by(Sort.Direction.DESC,"postedDate"))).getContent();var p=preference();var apps=applications.findAll();Set<UUID>tracked=apps.stream().map(a->a.getJob().getId()).collect(Collectors.toSet());var discoverable=all.stream().filter(j->!tracked.contains(j.getId())).toList();var scored=discoverable.stream().map(j->matching.score(j,p)).sorted(Comparator.comparingInt(com.careeros.matching.domain.JobMatch::overallScore).reversed()).toList();LocalDate today=LocalDate.now();long follow=reminders(apps).size();Set<UUID> watched=watchlists.findAll().stream().flatMap(w->w.getCompanies().stream()).filter(WatchlistCompany::isEnabled).map(x->x.getCompany().getId()).collect(Collectors.toSet());long watchedNew=discoverable.stream().filter(j->today.equals(j.getPostedDate())&&watched.contains(j.getCompany().getId())).map(j->j.getCompany().getId()).distinct().count();return new Dashboard(countToday(discoverable),scored.stream().filter(x->x.overallScore()>=p.getMinimumScore()).count(),follow,watchedNew,scored.stream().limit(10).map(m->summary(m,null)).toList(),discoverable.stream().limit(10).map(j->summary(matching.score(j,p),null)).toList(),statistics(all,apps,all.stream().map(j->matching.score(j,p)).toList()));}
 public List<Reminder> reminders(){return reminders(applications.findAll());}private List<Reminder> reminders(List<JobApplication>a){LocalDate now=LocalDate.now();List<Reminder>out=new ArrayList<>();for(var x:a){if(x.getFollowUpDate()!=null&&!x.getFollowUpDate().isAfter(now))out.add(new Reminder(x.getId(),"FOLLOW_UP_DUE",x.getFollowUpDate(),"Follow up with "+or(x.getRecruiterName(),"recruiter")));if(x.getInterviewDate()!=null&&x.getInterviewDate().equals(now.plusDays(1)))out.add(new Reminder(x.getId(),"INTERVIEW_TOMORROW",x.getInterviewDate(),"Interview tomorrow"));if(x.getAppliedDate()!=null&&x.getStatus()==ApplicationStatus.APPLIED&&ChronoUnit.DAYS.between(x.getAppliedDate(),now)>=7)out.add(new Reminder(x.getId(),"NO_RESPONSE",now,"No recruiter response after 7 days"));if(x.getUpdatedAt()!=null&&!terminal(x.getStatus())&&x.getUpdatedAt().isBefore(Instant.now().minus(14,ChronoUnit.DAYS)))out.add(new Reminder(x.getId(),"INACTIVE",now,"Application inactive for 14 days"));}return out;}
 public Map<String,Object> analytics(){var all=jobs.findAll(JobPostingFilter.empty(),PageRequest.of(0,1000)).getContent();var apps=applications.findAll();var scored=all.stream().map(j->matching.score(j,preference())).toList();return statistics(all,apps,scored);}
 public Page<JobSummary> timeline(LocalDate from,UUID company,Integer minScore,Boolean remote,String location,String ats,JobSourceType sourceType,Pageable pageable){var p=preference();Map<UUID,ApplicationStatus>statuses=applicationStatuses();var filter=new JobPostingFilter(company,null,location,null,remote,from,sourceType);var ingestionOrder=PageRequest.of(pageable.getPageNumber(),pageable.getPageSize(),Sort.by(Sort.Direction.DESC,"createdAt"));if(minScore==null&&ats==null)return jobs.findAll(filter,ingestionOrder).map(j->summary(matching.score(j,p),statuses.get(j.getId())));var candidates=jobs.findAll(filter,PageRequest.of(0,5000,Sort.by(Sort.Direction.DESC,"createdAt"))).getContent().stream().map(j->matching.score(j,p)).filter(m->minScore==null||m.overallScore()>=minScore).filter(m->ats==null||m.job().getCompany().getAtsType().name().equalsIgnoreCase(ats)).map(m->summary(m,statuses.get(m.job().getId()))).toList();int start=Math.min((int)pageable.getOffset(),candidates.size()),end=Math.min(start+pageable.getPageSize(),candidates.size());return new PageImpl<>(candidates.subList(start,end),pageable,candidates.size());}
 private Map<String,Object>statistics(List<JobPosting>jobs,List<JobApplication>apps,List<com.careeros.matching.domain.JobMatch>scores){long applied=apps.stream().filter(a->a.getAppliedDate()!=null&&YearMonth.from(a.getAppliedDate()).equals(YearMonth.now())).count();long responses=apps.stream().filter(a->a.getStatus().ordinal()>=ApplicationStatus.RECRUITER_CONTACTED.ordinal()&&!terminalNegative(a.getStatus())).count();long interviews=apps.stream().filter(a->Set.of(ApplicationStatus.RECRUITER_SCREEN,ApplicationStatus.TECHNICAL_INTERVIEW,ApplicationStatus.SYSTEM_DESIGN,ApplicationStatus.BEHAVIORAL,ApplicationStatus.FINAL_INTERVIEW,ApplicationStatus.OFFER).contains(a.getStatus())).count();Map<String,Object>m=new LinkedHashMap<>();m.put("applicationsThisMonth",applied);m.put("responseRate",rate(responses,apps.size()));m.put("interviewRate",rate(interviews,apps.size()));m.put("offerRate",rate(apps.stream().filter(a->a.getStatus()==ApplicationStatus.OFFER).count(),apps.size()));m.put("averageMatchScore",scores.stream().mapToInt(x->x.overallScore()).average().orElse(0));m.put("applicationsByStatus",apps.stream().collect(Collectors.groupingBy(a->a.getStatus().name(),Collectors.counting())));m.put("jobsByAts",jobs.stream().collect(Collectors.groupingBy(j->j.getCompany().getAtsType().name(),Collectors.counting())));m.put("jobsAppliedPerCompany",apps.stream().collect(Collectors.groupingBy(a->a.getJob().getCompany().getName(),Collectors.counting())));return m;}
 private UserPreference preference(){return prefs.findAll(PageRequest.of(0,1,Sort.by(Sort.Direction.DESC,"updatedAt"))).stream().findFirst().orElseGet(()->UserPreference.create(List.of("Senior Software Engineer","Senior Backend Engineer","Staff Engineer","Platform Engineer","Distributed Systems Engineer"),List.of("Java","Spring","Spring Boot","Kafka","AWS","Kubernetes","Docker","Terraform","PostgreSQL"),List.of(),0,false));}private long countToday(List<JobPosting>j){return j.stream().filter(x->LocalDate.now().equals(x.getPostedDate())).count();}private boolean terminal(ApplicationStatus s){return s==ApplicationStatus.OFFER||terminalNegative(s);}private boolean terminalNegative(ApplicationStatus s){return s==ApplicationStatus.REJECTED||s==ApplicationStatus.WITHDRAWN;}private double rate(long n,long d){return d==0?0:Math.round(n*1000.0/d)/10.0;}private String or(String x,String d){return x==null||x.isBlank()?d:x;}private Map<UUID,ApplicationStatus>applicationStatuses(){return applications.findAll().stream().collect(Collectors.toMap(a->a.getJob().getId(),JobApplication::getStatus,(first,second)->second));}private JobSummary summary(com.careeros.matching.domain.JobMatch m,ApplicationStatus status){var j=m.job();return new JobSummary(j.getId(),j.getTitle(),j.getCompany().getName(),j.getLocation(),j.isRemote(),j.getPostedDate(),j.getApplyUrl(),j.getSourceType(),j.getSourceUrl(),m.overallScore(),m.roleScore(),m.technologyScore(),m.locationScore(),m.companyPriorityScore(),m.recencyScore(),m.matchExplanation(),status);}
 public record JobSummary(UUID id,String title,String company,String location,boolean remote,LocalDate postedDate,String applyUrl,JobSourceType sourceType,String sourceUrl,int overallScore,int roleScore,int technologyScore,int locationScore,int companyPriorityScore,int recencyScore,List<String>matchExplanation,ApplicationStatus applicationStatus){}public record Dashboard(long newJobsToday,long highMatchJobs,long applicationsNeedingFollowUp,long watchlistCompaniesWithNewJobs,List<JobSummary>topMatches,List<JobSummary>recentJobs,Map<String,Object>statistics){}public record Reminder(UUID applicationId,String type,LocalDate dueDate,String message){}
}
